	}
	if resultRev == baseRev {
		outcome = ExecuteBeadOutcomeTaskNoChanges
	}
	return &ExecuteBeadResult{
		BeadID:    beadID,
		BaseRev:   baseRev,
		ResultRev: resultRev,
		ExitCode:  exitCode,
		Outcome:   outcome,
	}
