func TestCleanupAttemptWorktree_RemovesNonSuccessOutcomes(t *testing.T) {
	outcomes := []string{
		FailureModeProviderConnectivity,
		ExecuteBeadStatusNoEvidenceProduced,
		ExecuteBeadStatusExecutionFailed,
		ExecuteBeadStatusStructuralValidationFailed,
		ExecuteBeadStatusLandConflict,
		ExecuteBeadStatusPostRunCheckFailed,
	}

	for _, outcome := range outcomes {
		t.Run(outcome, func(t *testing.T) {
			gitOps := &attemptCleanupGitOps{}
			cleaned, err := cleanupAttemptWorktree(gitOps, "/repo", "/wt/"+outcome, outcome, false)
			if err != nil {
				t.Fatalf("cleanupAttemptWorktree(%q) error = %v", outcome, err)
			}
			if !cleaned {
				t.Fatalf("cleanupAttemptWorktree(%q) cleaned = false, want true", outcome)
			}
			if len(gitOps.removed) != 1 || gitOps.removed[0] != "/repo|/wt/"+outcome {
				t.Fatalf("WorktreeRemove calls = %#v, want one call for %q", gitOps.removed, outcome)
			}
		})
	}
}

func TestCleanupAttemptWorktree_KeepsSuccessOutcome(t *testing.T) {
	gitOps := &attemptCleanupGitOps{}
	cleaned, err := cleanupAttemptWorktree(gitOps, "/repo", "/wt/success", ExecuteBeadOutcomeTaskSucceeded, false)
	if err != nil {
		t.Fatalf("cleanupAttemptWorktree success error = %v", err)
	}
	if cleaned {
		t.Fatal("cleanupAttemptWorktree success cleaned = true, want false")
	}
	if len(gitOps.removed) != 0 {
		t.Fatalf("WorktreeRemove calls = %#v, want none", gitOps.removed)
	}
